eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   allCaseStudyParams: () => (/* binding */ allCaseStudyParams),\n/* harmony export */   caseStudies: () => (/* binding */ caseStudies),\n/* harmony export */   getCaseStudy: () => (/* binding */ getCaseStudy)\n/* harmony export */ });\nconst caseStudies = [\n    {\n        slug: \"core-banking-platform-modernization\",\n        tag: \"Financial Services\",\n        subtag: \"Cloud \\xb7 Custom Software\",\n        title: \"Core Banking Platform Modernization\",\n        description: \"Migrated a regional bank’s on-prem core system to AWS, reducing infrastructure costs by 34% and cutting release cycles from quarterly to bi-weekly.\",\n        image: \"/images/bank-office.jpg\",\n        client: \"Regional Retail Bank\",\n        industry: \"Financial Services\",\n        location: \"Ontario, Canada\",\n        duration: \"9 months\",\n        servicesUsed: [\n            \"Cloud Solutions\",\n            \"Custom Software Development\",\n            \"Cyber Security\"\n        ],\n        summary: \"A regional retail bank was running its core banking system on aging on-premises infrastructure, which limited its ability to ship new features and made every release a high-risk, quarterly event.\",\n        challenge: \"The bank’s core platform had been extended for over a decade on physical servers nearing end of life. Every release required a full weekend change window, regression testing was largely manual, and scaling for seasonal transaction spikes meant over-provisioning hardware that sat idle the rest of the year. Leadership needed a modernization path that would not put customer-facing banking services at risk during the transition.\",\n        solution: \"We ran a phased migration that re-platformed the core system onto AWS while keeping the bank fully operational throughout. Rather than a risky big-bang cutover, we built a parallel cloud environment, validated transaction parity against the legacy system, and moved workloads over in stages behind a feature-flagged routing layer.\",\n        solutionPoints: [\n            \"Re-architected the core banking application into containerized services deployed on AWS ECS\",\n            \"Built an automated CI/CD pipeline with staged rollouts, replacing manual quarterly release windows\",\n            \"Implemented infrastructure-as-code so environments could be reproduced and scaled on demand\",\n            \"Ran a dual-write validation period to confirm transaction parity before decommissioning legacy servers\",\n            \"Layered in enhanced monitoring, encryption at rest, and access controls to strengthen the security posture during the move\"\n        ],\n        results: \"The bank now ships updates every two weeks instead of once a quarter, with far less manual regression testing. Infrastructure costs dropped as the team moved from fixed over-provisioned hardware to elastic cloud capacity, and the bank gained the ability to scale automatically during peak transaction periods.\",\n        metrics: [\n            {\n                label: \"Infrastructure cost reduction\",\n                value: \"34%\"\n            },\n            {\n                label: \"Release cycle\",\n                value: \"Quarterly → Bi-weekly\"\n            },\n            {\n                label: \"Migration downtime\",\n                value: \"Zero\"\n            },\n            {\n                label: \"Uptime since launch\",\n                value: \"99.95%\"\n            }\n        ],\n        testimonial: {\n            quote: \"The team moved us off infrastructure that was over a decade old without a single disruption to customer-facing banking services. We now ship in weeks, not quarters.\",\n            author: \"VP of Technology\",\n            role: \"Regional Retail Bank\"\n        }\n    },\n    {\n        slug: \"patient-data-integration-hub\",\n        tag: \"Healthcare\",\n        subtag: \"Data & Integration \\xb7 Security\",\n        title: \"Patient Data Integration Hub\",\n        description: \"Built a HIPAA-compliant data integration layer connecting EHR systems across a multi-site Ontario health network, enabling real-time patient access.\",\n        image: \"/images/team-dashboard.jpg\",\n        client: \"Multi-Site Health Network\",\n        industry: \"Healthcare\",\n        location: \"Ontario, Canada\",\n        duration: \"7 months\",\n        servicesUsed: [\n            \"Data Engineering\",\n            \"Cyber Security\",\n            \"Custom Software Development\"\n        ],\n        summary: \"A multi-site Ontario health network needed clinicians at any location to see a complete, up-to-date patient record, but each site ran a different electronic health record (EHR) system with no shared integration layer.\",\n        challenge: \"Patient data was siloed across separate EHR systems at each site, so a patient seen at one location could have their history unavailable, delayed, or incomplete at another. Manual record transfers introduced delays and risk. Any integration layer also had to meet strict HIPAA and PHIPA data protection requirements while giving clinicians fast, reliable access.\",\n        solution: \"We designed and built a HIPAA-compliant integration hub that connects each site’s EHR system through standardized HL7/FHIR interfaces, normalizes patient records into a unified view, and makes that view available to clinicians in real time without duplicating or exposing more data than necessary.\",\n        solutionPoints: [\n            \"Built HL7/FHIR-based connectors for each site’s existing EHR system\",\n            \"Designed a normalized patient data model to reconcile records across sites\",\n            \"Implemented field-level encryption, audit logging, and role-based access controls\",\n            \"Delivered a real-time patient lookup interface for clinical staff\",\n            \"Ran a compliance review against HIPAA and PHIPA requirements before go-live\"\n        ],\n        results: \"Clinicians across the network can now pull a unified patient record in real time regardless of which site originally captured it, cutting down on delays and duplicate data entry, while every access event is logged for compliance and audit purposes.\",\n        metrics: [\n            {\n                label: \"Sites connected\",\n                value: \"6\"\n            },\n            {\n                label: \"Record lookup time\",\n                value: \"< 2 sec\"\n            },\n            {\n                label: \"Data access\",\n                value: \"Real-time\"\n            },\n            {\n                label: \"Compliance\",\n                value: \"HIPAA / PHIPA\"\n            }\n        ],\n        testimonial: {\n            quote: \"For the first time, our clinicians see one consistent patient record no matter which site they’re working from. The security review process was thorough and gave our compliance team real confidence.\",\n            author: \"Director of Clinical Systems\",\n            role: \"Multi-Site Health Network\"\n        }\n    },\n    {\n        slug: \"real-time-fleet-management-system\",\n        tag: \"Logistics & Supply Chain\",\n        subtag: \"Custom Software \\xb7 Managed IT\",\n        title: \"Real-Time Fleet Management System\",\n        description: \"Delivered a custom fleet tracking and dispatch platform for a cross-border logistics operator, processing 2M+ telemetry events per day with 99.97% uptime.\",\n        image: \"/images/ops-center.jpg\",\n        client: \"Cross-Border Logistics Operator\",\n        industry: \"Logistics & Supply Chain\",\n        location: \"Canada & United States\",\n        duration: \"11 months\",\n        servicesUsed: [\n            \"Custom Software Development\",\n            \"Managed IT\",\n            \"Cloud Solutions\"\n        ],\n        summary: \"A cross-border logistics operator needed real-time visibility into its fleet across two countries, but was relying on a patchwork of spreadsheets, driver phone calls, and a legacy dispatch tool that couldn’t keep up with volume.\",\n        challenge: \"Dispatchers had no live view of vehicle location, delays, or capacity, which meant reactive routing decisions and frequent missed delivery windows. The operator needed a system that could ingest telemetry from thousands of vehicles across the US-Canada border, process it in real time, and hand dispatchers the tools to act on it immediately, all without downtime that would stall shipments.\",\n        solution: \"We built a custom fleet tracking and dispatch platform from the ground up, designed to ingest high-volume telemetry streams and surface live fleet status, routing, and exceptions to dispatchers on a single operations dashboard.\",\n        solutionPoints: [\n            \"Built a real-time telemetry ingestion pipeline handling GPS, fuel, and status data from onboard devices\",\n            \"Designed a live dispatch dashboard showing fleet position, ETAs, and exceptions across both countries\",\n            \"Implemented automated alerting for delays, route deviations, and maintenance flags\",\n            \"Deployed on redundant cloud infrastructure to meet a high-availability uptime target\",\n            \"Set up managed IT support and monitoring for ongoing 24/7 operational reliability\"\n        ],\n        results: \"Dispatchers now have live visibility into the entire fleet and can proactively reroute around delays instead of reacting to missed windows. The platform reliably processes millions of telemetry events daily with minimal downtime, even during peak cross-border shipping volume.\",\n        metrics: [\n            {\n                label: \"Telemetry events processed\",\n                value: \"2M+ / day\"\n            },\n            {\n                label: \"System uptime\",\n                value: \"99.97%\"\n            },\n            {\n                label: \"Vehicles tracked\",\n                value: \"800+\"\n            },\n            {\n                label: \"On-time delivery improvement\",\n                value: \"+18%\"\n            }\n        ],\n        testimonial: {\n            quote: \"We went from phone calls and spreadsheets to a live operations dashboard our dispatchers actually rely on every day. The platform hasn’t missed a beat, even at peak volume.\",\n            author: \"Director of Operations\",\n            role: \"Cross-Border Logistics Operator\"\n        }\n    }\n];\nfunction getCaseStudy(slug) {\n    return caseStudies.find((c)=>c.slug === slug);\n}\nfunction allCaseStudyParams() {\n    return caseStudies.map((c)=>({\n            slug: c.slug\n        }));\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./lib/case-studies-data.ts\n");

